import { fuzzyMatch } from '../../utils/fuzzy_search';
import {
  isBooleanRecord,
  isStringArray,
  storageGet,
  storageSet,
} from '../../utils/storage';
import { ActionPanel } from '../action_panel/action_panel';
import {
  ClipboardHUDIcon,
  createCopyAction,
  createOpenInBrowserAction,
