        style: 'destructive',
        onAction: () => {
          setEntries(prev => {
            const next = prev.filter(e => e.id !== entryId);
            saveEntryState(next);
            return next;
          });
          showHUD({
            icon: <ClipboardHUDIcon />,
            title: 'Deleted',
          });
        },
      },
      dismissAction: {
        label: 'Cancel',
        style: 'cancel',
        onAction: () => {},
      },
    });
  }, [
    selectedEntry,
    confirmAlert,
    showHUD,
  ]);

  const handleAction = useCallback(() => {
    handlePaste();
  }, [handlePaste]);

  const toggleActions = useCallback(() => {
    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut(
    {
      key: 'k',
      meta: true,
    },
    toggleActions,
  );

  useKeyboardShortcut(
    {
      key: 'c',
      meta: true,
    },
    handleCopy,
  );

  useKeyboardShortcut(
    {
      key: 'p',
      meta: true,
      shift: true,
    },
    handleTogglePin,
  );

  useKeyboardShortcut(
    {
      key: 'Backspace',
      meta: true,
    },
    handleDelete,
  );

  const dropdownSections: DropdownSection[] = useMemo(
    () => {
      const primaryActions = [
        {
          label: 'Paste',
          shortcut: <Kbd keys={['↵']} />,
          onClick: handlePaste,
        },
        createCopyAction(
          {
            content: selectedEntry?.content ?? '',
            title: 'Copy',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'C',
                ]}
              />
            ),
            hudIcon: <ClipboardHUDIcon />,
          },
          showHUD,
        ),
      ];

      if (selectedEntry?.contentType === 'link') {
        primaryActions.push(
          createOpenInBrowserAction(
            {
              url: selectedEntry.content,
              shortcut: (
                <Kbd
                  keys={[
                    '⌘',
                    'O',
                  ]}
                />
              ),
            },
            showHUD,
          ),
        );
      }

      return [
      {
        title: 'Actions',
        actions: primaryActions,
      },
      {
        title: 'Organize',
        actions: [
          {
            label: selectedEntry?.pinned ? 'Unpin' : 'Pin',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  '⇧',
                  'P',
                ]}
              />
            ),
            onClick: handleTogglePin,
          },
        ],
      },
      {
        title: 'Danger Zone',
        actions: [
          {
            label: 'Delete',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  '⌫',
                ]}
              />
            ),
            onClick: handleDelete,
          },
        ],
      },
    ],
    [
      selectedEntry?.pinned,
      selectedEntry?.content,
      handlePaste,
      handleTogglePin,
      handleDelete,
      showHUD,
    ],
  );

  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder="Search Clipboard History..."
        activeDescendantId={activeDescendantId}
        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
        dropdown={
          <SearchDropdown
            sections={FILTER_SECTIONS}
            value={filterValue}
            onChange={handleFilterChange}
          />
        }
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          {totalItemCount === 0 ? (
            <EmptyState
              icon={<SearchEmptyIcon />}
              title="No Results"
              description="Try a different search term"
            />
          ) : (
            <List
              itemCount={totalItemCount}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleAction}
            >
              {(() => {
                let globalIndex = 0;

                const sections: ReactNode[] = [];

                if (pinnedItems.length > 0) {
                  sections.push(
                    <ListSection key="pinned" title="Pinned">
                      {pinnedItems.map(entry => {
                        const idx = globalIndex++;
                        return (
                          <ListItem
                            key={entry.id}
                            index={idx}
                            icon={renderClipboardIcon(entry)}
                            title={truncateContent(entry.content, 60)}
                            subtitle={entry.sourceApp}
                            accessories={[
                              {
                                text: formatRelativeDate(entry.copiedAt, now),
                                tooltip: entry.copiedAt.toLocaleString(),
                              },
                            ]}
                            query={query || undefined}
                          />
                        );
                      })}
                    </ListSection>,
                  );
                }

                if (recentItems.length > 0) {
                  sections.push(
                    <ListSection key="recent" title="Recent">
                      {recentItems.map(entry => {
                        const idx = globalIndex++;
                        return (
                          <ListItem
                            key={entry.id}
                            index={idx}
                            icon={renderClipboardIcon(entry)}
                            title={truncateContent(entry.content, 60)}
                            subtitle={entry.sourceApp}
                            accessories={[
                              {
                                text: formatRelativeDate(entry.copiedAt, now),
                                tooltip: entry.copiedAt.toLocaleString(),
                              },
                            ]}
                            query={query || undefined}
                          />
                        );
                      })}
                    </ListSection>,
                  );
                }

                return sections;
              })()}
            </List>
          )}
        </div>
      </div>
      <ActionPanel
        contextLabel="Clipboard History"
        actions={[
          {
            label: 'Paste',
            shortcut: <Kbd keys={['↵']} />,
          },
          {
            label: 'Actions',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'K',
                ]}
              />
            ),
            onClick: toggleActions,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={closeActions}
      />
      {alertState && (
        <Alert
          title={alertState.title}
          message={alertState.message}
          icon={alertState.icon}
          primaryAction={alertState.primaryAction}
          dismissAction={alertState.dismissAction}
          onDismiss={dismissAlert}
        />
      )}
      <HUDContainer items={hudItems} />
    </>
  );
}

