  const filtered = useMemo(() => {
    let items = entries;
    if (filterValue !== 'all') {
      items = items.filter(e => e.fileType === filterValue);
    }
    if (query) {
      items = items.filter(
        e => fuzzyMatch(query, e.name) || fuzzyMatch(query, e.path),
      );
    }
    return items;
  }, [
    entries,
    query,
    filterValue,
  ]);

  const folders = useMemo(
    () => filtered.filter(e => e.fileType === 'folder'),
    [filtered],
  );
  const files = useMemo(
    () => filtered.filter(e => e.fileType !== 'folder'),
    [filtered],
