            icon: <CopyHUDIcon />,
            title: `Moved "${entryName}" to Trash`,
          });
        },
      },
      dismissAction: {
        label: 'Cancel',
        style: 'cancel',
        onAction: () => {},
      },
    });
  }, [
    selectedEntry,
    confirmAlert,
    showHUD,
  ]);

  const handleAction = useCallback(() => {
    handleOpen();
  }, [handleOpen]);

  const toggleActions = useCallback(() => {
    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut(
    {
      key: 'k',
      meta: true,
    },
    toggleActions,
  );
  useKeyboardShortcut(
    {
      key: 'c',
      meta: true,
    },
    handleCopyPath,
  );
  useKeyboardShortcut(
    {
      key: 'f',
      meta: true,
      shift: true,
